--
-- Table structure for table `wa_lpn`
--

CREATE TABLE `wa_lpn` (
  `id` int(10) NOT NULL,
  `title` varchar(255) NOT NULL DEFAULT '0',
  `title1` varchar(255) NOT NULL DEFAULT '0',
  `title2` varchar(255) NOT NULL DEFAULT '0',
  `type` int(2) NOT NULL,
  `summery` text NOT NULL,
  `details` longtext NOT NULL,
  `day` int(2) NOT NULL DEFAULT 0,
  `month` int(2) NOT NULL DEFAULT 0,
  `year` int(4) NOT NULL DEFAULT 0,
  `pm_am` text NOT NULL,
  `time` varchar(40) NOT NULL DEFAULT '',
  `pic` varchar(100) NOT NULL DEFAULT '',
  `counter` int(20) NOT NULL,
  `send_count` int(10) NOT NULL DEFAULT 0,
  `print_count` int(10) NOT NULL DEFAULT 0,
  `writer` varchar(40) NOT NULL DEFAULT '',
  `pic_comment` varchar(888) NOT NULL,
  `inorder` int(11) NOT NULL,
  `important` int(11) NOT NULL,
  `vedio` int(11) NOT NULL,
  `sound` int(11) DEFAULT NULL,
  `photos` int(11) NOT NULL,
  `activerep` int(11) NOT NULL
) ENGINE=MyISAM DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

